const msg = $input.first().json;
const photo = msg.message?.photo;
if (!photo) return [{ json: { skip: true } }];
const caption = msg.message?.caption || '';
const parts = caption.split('|').map(s => s.trim());
if (parts.length < 4) return [{ json: { skip: true, reason: 'bad format' } }];
const [title, price, zona, hab, banos, m2, tipo] = parts;
return [{ json: {
  title: title || 'Nueva propiedad',
  price: parseFloat(price?.replace(/[^\d.]/g,'') || '0'),
  location: zona,
  bedrooms: parseInt(hab || '0'),
  bathrooms: parseInt(banos || '0'),
  area_sqm: parseInt(m2 || '0'),
  channel: tipo?.toLowerCase().includes('alquiler') ? 'alquiler' : tipo?.toLowerCase().includes('bancaria') ? 'bancaria' : 'personal',
  is_active: true,
  is_featured: false,
  fileId: photo[photo.length-1].file_id,
  chatId: msg.message.chat.id
} }];
